import 'package:flutter/material.dart';\nimport 'admin_dashboard.dart';\nimport 'map_monitoring.dart';\nimport 'alerts_management.dart';\nimport 'analytics.dart';\n\nclass InfrastructureManagement extends StatelessWidget {\n  @override\n  Widget build(BuildContext context) {\n    return Scaffold(\n      appBar: AppBar(\n        title: Text('Infrastructure Management'),\n        backgroundColor: Colors.red,\n      ),\n      endDrawer: _buildNavDrawer(context),\n      body: ListView(\n        padding: EdgeInsets.all(16),\n        children: [\n          _buildInfraCard('Roads & Highways', '45 Assets', Icons.directions_car, Colors.blue),\n          _buildInfraCard('Bridges & Tunnels', '12 Assets', Icons.architecture, Colors.orange),\n          _buildInfraCard('Power Grid', '8 Zones', Icons.electrical_services, Colors.green),\n          _buildInfraCard('Water Systems', '15 Plants', Icons.water_drop, Colors.cyan),\n          _buildInfraCard('Public Transport', '25 Lines', Icons.train, Colors.purple),\n        ],\n      ),\n    );\n  }\n\n  Widget _buildInfraCard(String title, String count, IconData icon, Color color) {\n    return Card(\n      margin: EdgeInsets.symmetric(vertical: 8),\n      child: ListTile(\n        leading: CircleAvatar(backgroundColor: color, child: Icon(icon, color: Colors.white)),\n        title: Text(title),\n        subtitle: Text(count),\n        trailing: Icon(Icons.edit),\n      ),\n    );\n  }\n\n  Widget _buildNavDrawer(BuildContext context) {\n    return Drawer(\n      child: ListView(\n        children: [\n          DrawerHeader(\n            decoration: BoxDecoration(color: Colors.red),\n            child: Text('Admin Menu', style: TextStyle(color: Colors.white, fontSize: 24)),\n          ),\n          ListTile(\n            leading: Icon(Icons.dashboard),\n            title: Text('Dashboard'),\n            onTap: () => Navigator.push(context, MaterialPageRoute(builder: (context) => AdminDashboard())),\n          ),\n          ListTile(\n            leading: Icon(Icons.build),\n            title: Text('Infrastructure'),\n            onTap: () => Navigator.pop(context),\n          ),\n          ListTile(\n            leading: Icon(Icons.map),\n            title: Text('Map Monitoring'),\n            onTap: () => Navigator.push(context, MaterialPageRoute(builder: (context) => MapMonitoring())),\n          ),\n          ListTile(\n            leading: Icon(Icons.warning),\n            title: Text('Alerts'),\n            onTap: () => Navigator.push(context, MaterialPageRoute(builder: (context) => AlertsManagement())),\n          ),\n          ListTile(\n            leading: Icon(Icons.analytics),\n            title: Text('Analytics'),\n            onTap: () => Navigator.push(context, MaterialPageRoute(builder: (context) => Analytics())),\n          ),\n        ],\n      ),\n    );\n  }\n}